(6066, '_site_transient_ithemes-security-news', 'a:19:{s:2:\"id\";i:101772;s:4:\"date\";s:19:\"2024-09-25T06:33:17\";s:4:\"slug\";s:48:\"wordpress-vulnerability-report-september-25-2024\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:74:\"https://solidwp.com/blog/wordpress-vulnerability-report-september-25-2024/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:53:\"WordPress Vulnerability Report — September 25, 2024\";}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:244:\"<p>Since last week, 72 new vulnerabilities emerged in the WordPress ecosystem including 66 plugins and 6 themes. 24 of the vulnerable plugins remain unpatched, but Solid Security Pro users are protected by virtual patching from Patchstack.</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:59680;s:14:\"featured_media\";i:94496;s:3:\"acf\";a:0:{}s:10:\"yoast_head\";s:5845:\"<!-- This site is optimized with the Yoast SEO Premium plugin v20.8 (Yoast SEO v23.3) - https://yoast.com/wordpress/plugins/seo/ -->\n<title>WordPress Vulnerability Report — September 25, 2024 - SolidWP</title>\n<meta name=\"description\" content=\"Since last week, 72 new vulnerabilities emerged in the WordPress ecosystem including 66 plugins and 6 themes. 24 of the vulnerable plugins remain unpatched, but Solid Security Pro users are protected by virtual patching from Patchstack.\" />\n<meta name=\"robots\" content=\"index, follow, max-snippet:-1, max-image-preview:large, max-video-preview:-1\" />\n<link rel=\"canonical\" href=\"https://solidwp.com/blog/wordpress-vulnerability-report-september-25-2024/\" />\n<meta property=\"og:locale\" content=\"en_US\" />\n<meta property=\"og:type\" content=\"article\" />\n<meta property=\"og:title\" content=\"WordPress Vulnerability Report — September 25, 2024\" />\n<meta property=\"og:description\" content=\"Each week, we report the latest vulnerabilities in WordPress plugins and themes. Vulnerable WordPress plugins and themes are among the reasons WordPress sites get hacked.\" />\n<meta property=\"og:url\" content=